// Enrich Selected 10 — Parse (handles N items, recomputes fingerprint)
const required = [
  'business_name','category','address','phone','website',
  'public_rating','review_count',
  'website_issues','heuristic_assessment','services_listed','tech_signals',
  'freshness_signal','operating_status',
  'opportunity_score','why_lead','source_links'
];

function norm(s) {
  return (s || '').toString().toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/[^\p{L}\p{N}\s]/gu, '')
    .trim();
}
function host(url) {
  try { if (!url) return ''; return new URL(url).hostname.replace(/^www\./, '').toLowerCase(); }
  catch { return ''; }
}
function makeFp(j) {
  const name = norm(j.business_name);
  const addr = norm(j.address);
  const phone = norm(j.phone);
  const whost = host(j.website);
  if (name && addr) return `${name}|${addr}`;
  if (name && phone) return `${name}|${phone}`;
  if (name && whost) return `${name}|${whost}`;
  return name ? `${name}|` : null;
}

const out = [];
for (const item of items) {
  const r = item.json || {};
  let raw = r.output ?? r.text ?? r;

  let obj;
  if (typeof raw === 'string') {
    let cleaned = raw.trim().replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();
    try { obj = JSON.parse(cleaned); } catch { continue; }
  } else if (typeof raw === 'object' && raw !== null) {
    obj = raw;
  } else continue;

  if (obj.output && typeof obj.output === 'object') obj = obj.output;
  for (const k of required) if (!(k in obj)) obj[k] = null;

// Flatten arrays to strings for TEXT columns
const arrToStr = (v, sep = '; ') => Array.isArray(v) ? v.filter(Boolean).join(sep) : v;
obj.services_listed = arrToStr(obj.services_listed, ', ');
obj.tech_signals = arrToStr(obj.tech_signals, ', ');
obj.website_issues = arrToStr(obj.website_issues, '; ');
obj.source_links = arrToStr(obj.source_links, ' | ');
obj.public_rating = obj.public_rating != null ? String(obj.public_rating) : null;
obj.review_count = obj.review_count != null ? String(obj.review_count) : null;


  // Recompute fingerprint from enriched data (agent drops it)
  obj.fingerprint = makeFp(obj);

  out.push({ json: obj });
}

if (out.length === 0) {
  throw new Error('Parse produced 0 items. First input shape: ' + JSON.stringify(items[0]?.json).slice(0, 400));
}
return out;

// Enrich Selected 10 — Prep (no-LangChain edition)
function norm(s){return (s??'').toString().trim();}
return items.map(item=>{
  const j=item.json;
  const business_name=norm(j.business_name||j.name);
  const website=norm(j.website);
  const source_links=j.source_links ?? j.source_link ?? j.listing_url ?? j.url ?? null;
  const urls=[];
  if (Array.isArray(source_links)) urls.push(...source_links.filter(Boolean));
  else if (typeof source_links==='string' && source_links) urls.push(source_links);
  if (website) urls.push(website);
  return {json:{...j, business_name, website: website||null, source_links: source_links??null, enrichment_urls: urls}};
});

function norm(s) {
  return (s || '')
    .toString()
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .replace(/[^\p{L}\p{N}\s]/gu, '')
    .trim();
}

function host(url) {
  try {
    if (!url) return '';
    const u = new URL(url);
    return u.hostname.replace(/^www\./, '').toLowerCase();
  } catch {
    return '';
  }
}

return $input.all().map(item => {
  const j = item.json;
  const name = norm(j.business_name);
  const addr = norm(j.address);
  const phone = norm(j.phone);
  const whost = host(j.website);

  const fp =
    (name && addr) ? `${name}|${addr}` :
    (name && phone) ? `${name}|${phone}` :
    (name && whost) ? `${name}|${whost}` :
    name ? `${name}|` : null;

  return { json: { ...j, fingerprint: fp } };
});

const agentOutput = $input.first().json.output;

let leads = [];
try {
  const jsonMatch = agentOutput.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    leads = JSON.parse(jsonMatch[0]);
  } else {
    leads = JSON.parse(agentOutput);
  }
} catch (e) {
  return [{ json: { error: 'Failed to parse agent output', raw: agentOutput } }];
}

const weekOf = new Date().toISOString().split('T')[0];

return leads.map(lead => ({
  json: {
    business_name: lead.business_name || null,
    category: lead.category || null,
    address: lead.address || null,
    phone: lead.phone || null,
    website: lead.website || null,
    public_rating: lead.public_rating != null ? String(lead.public_rating) : null,
    review_count: lead.review_count != null ? String(lead.review_count) : null,
    website_issues: Array.isArray(lead.website_issues) 
      ? lead.website_issues.join('; ') 
      : (lead.website_issues || null),
    heuristic_assessment: lead.heuristic_assessment || null,
    services_listed: Array.isArray(lead.services_listed) 
      ? lead.services_listed.join(', ') 
      : (lead.services_listed || null),
    tech_signals: Array.isArray(lead.tech_signals) 
      ? lead.tech_signals.join(', ') 
      : (lead.tech_signals || null),
    freshness_signal: lead.freshness_signal || null,
    opportunity_score: lead.opportunity_score || null,
    why_lead: lead.why_lead || null,
    // handle both source_link and source_links
    source_links: lead.source_links || lead.source_link || null,
    week_of: weekOf,
    discovered_at: new Date().toISOString()
  }
}));

// Build a clean HTML email summarising the week's new leads
const raw = $input.all();
let leads = [];
if (raw.length === 1 && raw[0].json && Array.isArray(raw[0].json.data)) {
  leads = raw[0].json.data;
} else {
  leads = raw.map(i => i.json);
}

const weekOf = new Date().toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });

// Emojis
const scoreEmoji = (s) => s === 'High' ? '🚀' : s === 'Medium' ? '✅' : '🟡';

const safe = (v, f = '—') => (v === null || v === undefined || v === '') ? f : v;

// --- NEW: sort leads by opportunity_score (High -> Medium -> Low -> everything else) ---
const scoreRank = (s) => {
  const v = (s ?? '').toString().trim().toLowerCase();
  if (v === 'high') return 0;
  if (v === 'medium') return 1;
  if (v === 'low') return 2;
  return 3; // unknown / null / anything else goes last
};

// Stable-ish ordering: keep original order inside each group via original index
leads = leads
  .map((lead, idx) => ({ lead, idx }))
  .sort((a, b) => {
    const ra = scoreRank(a.lead.opportunity_score);
    const rb = scoreRank(b.lead.opportunity_score);
    if (ra !== rb) return ra - rb;
    return a.idx - b.idx;
  })
  .map(x => x.lead);

// Cell styles
const tdWrap = "padding:12px;color:#555;vertical-align:top;white-space:normal;overflow-wrap:anywhere;word-break:break-word;";
const tdWrapStrong = "padding:12px;font-weight:600;color:#111;vertical-align:top;white-space:normal;overflow-wrap:anywhere;word-break:break-word;";
const tdScore = "padding:12px;text-align:center;vertical-align:top;white-space:nowrap;";

const row = (lead, i) => `
  <tr style="background:${i % 2 === 0 ? '#ffffff' : '#f9f9f9'}">
    <td style="${tdWrapStrong}">${safe(lead.business_name)}</td>
    <td style="${tdWrap}text-align:left;">
      ${
        lead.website
          ? `<a href="${lead.website}" target="_blank" rel="noopener noreferrer">Website</a>`
          : '<em>No website</em>'
      }
    </td>
    <td style="${tdScore}">${scoreEmoji(lead.opportunity_score)} ${safe(lead.opportunity_score, '—')}</td>
    <td style="${tdWrap}font-size:13px;">${safe(lead.why_lead, '')}</td>
  </tr>`;

const html = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"></head>
<body style="font-family:Inter,Arial,sans-serif;background:#f4f4f4;padding:32px;margin:0">
  <div style="max-width:900px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.08)">
    <div style="background:#1a1a2e;padding:32px;color:#fff">
      <h1 style="margin:0;font-size:24px">🏗️ Marco's Lead Scout</h1>
      <p style="margin:8px 0 0;opacity:0.7">Week of ${weekOf} — ${leads.length} new lead${leads.length !== 1 ? 's' : ''} found</p>
    </div>
    <div style="padding:32px">
      <table style="width:100%;border-collapse:collapse;font-size:14px;table-layout:fixed">
        <thead>
          <tr style="background:#f0f0f0">
            <th style="padding:12px;text-align:left;color:#333;width:26%;white-space:normal;overflow-wrap:anywhere;">Business</th>
            <th style="padding:12px;text-align:left;color:#333;width:10%;white-space:nowrap;">Website</th>
            <th style="padding:12px;text-align:center;color:#333;width:10%;white-space:nowrap;">Score</th>
            <th style="padding:12px;text-align:left;color:#333;width:54%;white-space:normal;overflow-wrap:anywhere;">Why Contact</th>
          </tr>
        </thead>
        <tbody>
          ${leads.map((lead, i) => row(lead, i)).join('')}
        </tbody>
      </table>
      <p style="margin-top:32px;color:#999;font-size:12px">Made with love by your n8n workflow.</p>
    </div>
  </div>
</body>
</html>`;

return [{ json: { subject: `🏗️ Marco's Lead Scout — Week of ${weekOf} (${leads.length} new leads)`, html } }];

// Rotation seed for category/area diversity
// Picks a different rotation each week, deterministic by ISO week number
const now = new Date();
const start = new Date(now.getFullYear(), 0, 1);
const week = Math.ceil(((now - start) / 86400000 + start.getDay() + 1) / 7);

const categories = [
  ['Friseur', 'Restaurant', 'Fitnessstudio'],
  ['Fitnessstudio', 'Zahnarzt', 'Friseur'],
  ['Restaurant', 'Friseur', 'Zahnarzt'],
  ['Zahnarzt', 'Restaurant', 'Fitnessstudio']
];
const areas = [
  ['Mitte', 'Neukölln', 'Kreuzberg'],
  ['Charlottenburg', 'Wilmersdorf', 'Schöneberg'],
  ['Prenzlauer Berg', 'Friedrichshain', 'Pankow'],
  ['Spandau', 'Tempelhof', 'Steglitz']
];

const cat = categories[week % categories.length];
const area = areas[week % areas.length];

return [{
  json: {
    week_number: week,
    rotation_categories: cat,
    rotation_areas: area,
    rotation_hint: `This week focus on: categories=${cat.join(', ')}; neighbourhoods=${area.join(', ')}`
  }
}];

// Candidates come from Compute Fingerprint (one node back in the chain)
const candidates = $('Compute Fingerprint').all();
const seenItems = $('Fetch Seen Fingerprints').all();

const seen = new Set(
  seenItems.map(i => (i.json.fingerprint || '').trim()).filter(Boolean)
);

const unseen = candidates.filter(c => {
  const fp = (c.json.fingerprint || '').trim();
  return fp && !seen.has(fp);
});

return unseen.slice(0, 10);

// Return top 10
return unseen.slice(0, 10);
